+double polygon_area(const std::vector<Vec2D>& poly) {
+// https://www.wikiwand.com/en/Shoelace_formula
+  int n = poly.size();
+
+  double sum = 0;
+  for (int i = 0; i < n; ++i) {
+    double xi = poly[i].x;
+    double yi_next = poly[(i + 1) % n].y;
+    double yi_prev = poly[(i + n - 1) % n].y;
+    sum += xi * (yi_next - yi_prev);
+  }
+  return 0.5 * fabs(sum);
+}
