+    print_debug("Cannot estimate focal. Will use a naive one.\n");
+    f = 0.5 * (imgs[mid].width() + imgs[mid].height());
+  }
+  REP(i, n) {
+    auto M = Homography{{
+        1.0/f, 0,     0,
+        0,     1.0/f, 0,
+        0,     0,     1
+    }};
+    comp[i].homo = M * comp[i].homo;
+  }
   bundle.calc_inverse_homo();
 }

