+		I_R_e = vvec.cross(I_R_e);
+		ret[2] += cross_product_matrix(I_R_e.x, I_R_e.y, I_R_e.z);
+
+		REP(i, 3) {
+			ret[i].mult(1.0 / vsqr);
+			ret[i] = ret[i] * R;
+		}
 		return ret;
 	}

