+void Camera::straighten(std::vector<Camera>& cameras) {
+	GuardedTimer tm("straighten");
+	using namespace Eigen;
+	Matrix3d cov = Matrix3d::Zero();
+	for (auto& c : cameras) {
+		// R is from current image to reference image
