+ *int main() {
+ *  auto p = feature::gen_brief_pattern(9, 256);
+ *  for (auto& pair: p.pattern) {
+ *    cout << pair.first/9 << " " << pair.first % 9
+ *      << "->" << pair.second/ 9 << " " << pair.second %9<< endl;
+ *  }
+ *}
+ */
