-	dyy = img.at(y + 1, x) + img.at(y - 1, x) - val - val;
-	dxy = (img.at(y + 1, x + 1) + img.at(y - 1, x - 1) -
-			img.at(y + 1, x - 1) - img.at(y - 1, x + 1)) / 4;
