+//File: timer.cc
+//Date: Fri Apr 17 15:45:45 2015 +0800
+//Author: Yuxin Wu <ppwwyyxxc@gmail.com>
+
+#include "timer.hh"
+#include <mutex>
+
+// static member
+std::map<std::string, double> TotalTimer::rst;
+
+void TotalTimer::print() {
+	for (auto& itr : rst)
+		printf("%s spent %lf secs in total\n", itr.first.c_str(), itr.second);
+}
+
+TotalTimer::~TotalTimer() {
+	static std::mutex mt;
+	std::lock_guard<std::mutex> lg(mt);
+	rst[msg] += timer.duration();
+}
diff --git a/src/lib/timer.hh b/src/lib/timer.hh
new file mode 100644
index 0000000..954ef70
--- /dev/null
+++ b/src/lib/timer.hh
@@ -0,0 +1,91 @@
+/*
+ * $File: timer.hh
+ * $Date: Wed Apr 22 12:19:57 2015 +0800
+ * $Author: Xinyu Zhou <zxytim[at]gmail[dot]com>
+ */
+
+#pragma once
+
+#include <chrono>
+#include <functional>
+#include <memory>
+#include <map>
+#include <iostream>
+
+class Timer {
+	public:
+		using Clock = std::chrono::high_resolution_clock;
+		Timer() {
+			restart();
+		}
+
+		// return current unix timestamp
+		void restart() {
+			m_start_time = std::chrono::high_resolution_clock::now();
+		}
+
+		// return duration in seconds
+		double duration() const {
+			auto now = std::chrono::high_resolution_clock::now();
+			auto m = std::chrono::duration_cast<std::chrono::microseconds>(now - m_start_time).count();
+			return m * 1.0 / 1e6;
+		}
+
+	protected:
+		std::chrono::time_point<Clock> m_start_time;
+
+};
+
+
+class GuardedTimer: public Timer {
+	public:
+		GuardedTimer(std::string msg,  bool enabled=true):
+			GuardedTimer([msg](double duration){
+					std::cout << msg << ": " << duration * 1000. << " milliseconds." << std::endl;
+				})
+		{ enabled_ = enabled; }
+
+		GuardedTimer(std::function<void(double)> callback):
+			m_callback(callback)
+		{ }
+
+		~GuardedTimer() {
+			if (enabled_)
+				m_callback(duration());
+		}
+
+	protected:
+		bool enabled_;
+		std::function<void(double)> m_callback;
+
+};
+
+// record the total running time of a region across the lifecycle of the whole program
+// call TotalTimer::print() before exiting main()
+class TotalTimer {
+	public:
+		TotalTimer(const std::string& msg):
+			msg(msg) {
+				timer.restart();
+			}
+
+		~TotalTimer();
+
+		static void print();
+
+		std::string msg;
+		Timer timer;
+
+		static std::map<std::string, double> rst;
+};
+
