+        const T &at(int r, int c, int ch) const;
+
+        Mat<T> clone() const;
+
+        const T *ptr(int r = 0) const
+				{ return m_data.get() + r * m_cols * m_channels; }
+        T *ptr(int r = 0)
+				{ return m_data.get() + r * m_cols * m_channels; }
