+		m_assert(2 * M_PI + EPS >= theta);
+
+		theta = theta / (M_PI * 2) * w;
+
+		update_min(dist, (real_t)h - 1);
+		ret->set_pixel(i, j, test->get_pixel(dist, theta));
+	}
