+ConfigParser::ConfigParser(const char* fname) {
+	ifstream fin(fname);
+	string s;
+	double val;
+	while (fin >> s) {
+		if (s[0] == '#') {
+			fin.getline(&s[0], 255, '\n');
+			continue;
+		}
+		fin >> val;
+		data[s] = val;
+	}
+}
+
+double ConfigParser::get(const std::string& s) {
+	return data[s];
