+real_t TransFormer::get_focal_from_matrix(const Matrix& m) {
+	real_t f2;
+	real_t p1 = sqr(m.get(0, 0)) + sqr(m.get(0, 1)) - sqr(m.get(1, 0)) - sqr(m.get(1, 1));
+	if (fabs(p1) > EPS)  {
