+	r.normalize();
+	Vec vtmp = p.cross(q);
+	real_t dist = (vtmp - r).mod();
+	if (dist > 1e-6)
+		r = vtmp;
+	val[0][0] = p.x, val[1][0] = p.y, val[2][0] = p.z;
+	val[0][1] = q.x, val[1][1] = q.y, val[2][1] = q.z;
+	val[0][2] = r.x, val[1][2] = r.y, val[2][2] = r.z;
+}
+
+real_t Matrix::sqrsum() const {
+	m_assert(w == 1);
+	real_t sum = 0;
+	REP(i, h)
+		sum += sqr(val[i][0]);
+	return sum;
+}
+
+Matrix Matrix::col(int i) const {
+	m_assert(i < w);
+	Matrix ret(1, h);
+	REP(j, h)
+		ret.get(j, 0) = get(j, i);
+	return move(ret);
+}
